node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: false, args: ['--start-maximized'] });
  const ctx = await browser.newContext({ viewport: null });
  const page = await ctx.newPage();
  await page.goto('https://www.tapd.cn/cloud_logins/login', { waitUntil: 'domcontentloaded' });
  console.log('页面已打开，等待扫码...');
  // 等待跳转到 workspace（登录成功）
  await page.waitForURL('**/tapd.cn/**', { timeout: 120000 });
  console.log('登录成功！当前 URL:', page.url());
  // 保存 cookies
  const cookies = await ctx.cookies();
  require('fs').writeFileSync('tapd_cookies.json', JSON.stringify(cookies, null, 2));
  console.log('Cookie 已保存到 tapd_cookies.json');
  await browser.close();
})().catch(e => { console.error(e); process.exit(1); });
"

