node -e "
const cookies = JSON.parse(require('fs').readFileSync('tapd_cookies.json', 'utf8'));
const key = ['tapdsession', 't_u', 't_cloud_login', '_t_crop', '_t_uid'];
const result = cookies.filter(c => key.includes(c.name));
result.forEach(c => {
  const exp = c.expires > 0 ? new Date(c.expires * 1000).toLocaleString('zh-CN', {timeZone:'Asia/Shanghai'}) : '会话';
  console.log(c.name + ' = ' + c.value.substring(0, 30) + '...' + ' (到期: ' + exp + ')');
});
console.log('---');
// 找 t_u 用户信息
const tu = cookies.find(c => c.name === 't_u');
if (tu) {
  try {
    const decoded = decodeURIComponent(tu.value);
    console.log('t_u 解码:', decoded);
  } catch(e) { console.log('t_u raw:', tu.value); }
}
"

