  // 连接到已运行的 Chrome（需要 remote debugging 端口）
  // 先检查是否开了 debug 端口
  const http = require('http');
  http.get('http://localhost:9222/json', (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => console.log('debug port open:', data.substring(0,200)));
  }).on('error', () => console.log('no debug port'));
})();
"

node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: false, args: ['--start-maximized'] });
  const ctx = await browser.newContext({ viewport: null });
  const page = await ctx.newPage();
  await page.goto('https://www.tapd.cn/cloud_logins/login', { waitUntil: 'domcontentloaded' });
  console.log('页面已打开，等待扫码...');
  // 等待跳转到 workspace（登录成功）
  await page.waitForURL('**/tapd.cn/**', { timeout: 120000 });
  console.log('登录成功！当前 URL:', page.url());
  // 保存 cookies
  const cookies = await ctx.cookies();
  require('fs').writeFileSync('tapd_cookies.json', JSON.stringify(cookies, null, 2));
  console.log('Cookie 已保存到 tapd_cookies.json');
  await browser.close();
})().catch(e => { console.error(e); process.exit(1); });
"

node -e "
const cookies = JSON.parse(require('fs').readFileSync('tapd_cookies.json', 'utf8'));
const key = ['tapdsession', 't_u', 't_cloud_login', '_t_crop', '_t_uid'];
const result = cookies.filter(c => key.includes(c.name));
result.forEach(c => {
  const exp = c.expires > 0 ? new Date(c.expires * 1000).toLocaleString('zh-CN', {timeZone:'Asia/Shanghai'}) : '会话';
  console.log(c.name + ' = ' + c.value.substring(0, 30) + '...' + ' (到期: ' + exp + ')');
});
console.log('---');
// 找 t_u 用户信息
const tu = cookies.find(c => c.name === 't_u');
if (tu) {
  try {
    const decoded = decodeURIComponent(tu.value);
    console.log('t_u 解码:', decoded);
  } catch(e) { console.log('t_u raw:', tu.value); }
}
"

